CREATE OR REPLACE VIEW brain_serving.mv_metric_cm1_pct_all AS
WITH base AS (
  SELECT
    brand_id,
    currency_code,
    channel,
    SUM(cm1_minor) AS cm1_minor,
    SUM(net_revenue_minor) AS net_revenue_minor
